function preprocess(raw) {
  let clean = String(raw ?? "").trim();

  const shortcuts = {
    д: "Да",
    "+": "Да",
    "👍": "Да",
    н: "Нет",
    "-": "Нет",
    "👎": "Нет",
  };

  if (clean.length <= 2) {
    const k = clean.toLowerCase();
    if (Object.prototype.hasOwnProperty.call(shortcuts, k)) {
      clean = shortcuts[k];
    }
  }

  return clean;
}

return preprocess($question);

