const MAP = {
  default: {
    natural_followups: ["Имплантация", "Протезирование", "Гигиена"],
    video_url: "",
    pdf_url: "",
    final_cta: { text: "Что вас интересует в первую очередь?", buttons: [] }
  },
  implantation__pain: {
    topic: "implantation",
    subtopic: "pain",
    source_filename: "implantation__faq__pain.md",
    natural_followups: [
      "Почему не больно во время имплантации",
      "Какую анестезию используют при имплантации"
    ],
    video_url: "",
    pdf_url: "https://example.com/cesi/pain-after-care.pdf",
    pdf_title: "Памятка: боль и дискомфорт после лечения",
    final_cta: {
      text: "Если хотите, могу дать короткую памятку в PDF с базовыми ориентирами.",
      buttons: [
        "Скачать PDF",
        "Рассказать про обезболивание",
        "Записаться на консультацию"
      ]
    }
  }
};

function pickKeyFromContext(ctx) {
  const s = String(ctx || "");
  const topic = (s.match(/"topic"\s*:\s*"([^"]*)"/) || [])[1];
  const subtopic = (s.match(/"subtopic"\s*:\s*"([^"]*)"/) || [])[1];
  const filename = (s.match(/"filename"\s*:\s*"([^"]*)"/) || [])[1];

  if (topic && subtopic) {
    const k = topic + "__" + subtopic;
    if (MAP[k]) return k;
  }
  if (filename) {
    const base = filename.replace(/\.md$/i, "");
    if (MAP[base]) return base;
    const parts = base.split("__");
    if (parts.length >= 3) {
      const k2 = parts[0] + "__" + parts[parts.length - 1];
      if (MAP[k2]) return k2;
    }
  }
  return "default";
}

const key = pickKeyFromContext($flow.state.last_context);
return JSON.stringify(MAP[key] || MAP.default);

